input.content:
// Package port defines interfaces (ports) that usecases depend on.
// Adapters implement these interfaces.
package port

package port

import (
	"context"

	"github.com/nikitakovalevtaverz/chirp/internal/domain/user"
)

// UserRepository is the persistence port for users.
type UserRepository interface {
	Create(ctx context.Context, u *user.User) error
	GetByID(ctx context.Context, id string) (*user.User, error)
	GetByEmail(ctx context.Context, email string) (*user.User, error)
	GetByUsername(ctx context.Context, username string) (*user.User, error)
}

package port

import "context"

// TokenPair holds access and refresh tokens.
type TokenPair struct {
	AccessToken  string
	RefreshToken string
}

// AuthService issues and validates tokens.
type AuthService interface {
	IssueTokenPair(ctx context.Context, userID string) (*TokenPair, error)
	ValidateAccessToken(ctx context.Context, tokenString string) (string, error) // returns userID
}

package port

// PasswordHasher hashes and compares passwords.
type PasswordHasher interface {
	Hash(password string) (string, error)
	Compare(hash, password string) error
}

package user

// RegisterInput is the DTO for user registration.
type RegisterInput struct {
	Username string
	Email    string
	Password string
}

// LoginInput is the DTO for user login.
type LoginInput struct {
	Email    string
	Password string
}

// UserResponse is the public API representation of a user.
type UserResponse struct {
	ID          string `json:"id"`
	Username    string `json:"username"`
	Email       string `json:"email"`
	DisplayName string `json:"display_name"`
	Bio         string `json:"bio"`
	CreatedAt   string `json:"created_at"`
}

// AuthResponse is the response for login/register containing tokens.
type AuthResponse struct {
	User         UserResponse `json:"user"`
	AccessToken  string       `json:"access_token"`
	RefreshToken string       `json:"refresh_token"`
}

// FromUser maps a domain User to a UserResponse DTO.
func FromUser(u *domainUser) UserResponse {
	return UserResponse{
		ID:          u.ID,
		Username:    u.Username,
		Email:       u.Email,
		DisplayName: u.DisplayName,
		Bio:         u.Bio,
		CreatedAt:   u.CreatedAt.Format("2006-01-02T15:04:05Z"),
	}
}

package user

import (
	"context"

	"github.com/nikitakovalevtaverz/chirp/internal/domain/user"
	domainUser "github.com/nikitakovalevtaverz/chirp/internal/domain/user"
	"github.com/nikitakovalevtaverz/chirp/internal/port"
)

// RegisterUseCase handles user registration.
type RegisterUseCase struct {
	repo     port.UserRepository
	hasher   port.PasswordHasher
	authSvc  port.AuthService
}

// NewRegisterUseCase creates a RegisterUseCase with injected dependencies.
func NewRegisterUseCase(
	repo port.UserRepository,
	hasher port.PasswordHasher,
	authSvc port.AuthService,
) *RegisterUseCase {
	return &RegisterUseCase{repo: repo, hasher: hasher, authSvc: authSvc}
}

// Execute registers a new user and returns tokens.
func (uc *RegisterUseCase) Execute(ctx context.Context, input RegisterInput) (*AuthResponse, error) {
	// Validate username
	uname, err := user.NewUsername(input.Username)
	if err != nil {
		return nil, err
	}

	// Validate email
	email, err := user.NewEmail(input.Email)
	if err != nil {
		return nil, err
	}

	// Validate password
	pwd, err := user.NewPassword(input.Password)
	if err != nil {
		return nil, err
	}

	// Check uniqueness
	existing, _ := uc.repo.GetByEmail(ctx, string(email))
	if existing != nil {
		return nil, domainUser.ErrEmailTaken
	}
	existing, _ = uc.repo.GetByUsername(ctx, string(uname))
	if existing != nil {
		return nil, domainUser.ErrUsernameTaken
	}

	// Hash password
	hash, err := uc.hasher.Hash(string(pwd))
	if err != nil {
		return nil, err
	}

	// Create user
	u := &user.User{
		ID:           newID(),
		Username:     string(uname),
		Email:        string(email),
		PasswordHash: hash,
	}

	if err := uc.repo.Create(ctx, u); err != nil {
		return nil, err
	}

	// Issue tokens
	tokens, err := uc.authSvc.IssueTokenPair(ctx, u.ID)
	if err != nil {
		return nil, err
	}

	return &AuthResponse{
		User:         FromUser(u),
		AccessToken:  tokens.AccessToken,
		RefreshToken: tokens.RefreshToken,
	}, nil
}

package user

import (
	"context"

	domainUser "github.com/nikitakovalevtaverz/chirp/internal/domain/user"
	"github.com/nikitakovalevtaverz/chirp/internal/port"
)

// LoginUseCase handles user authentication.
type LoginUseCase struct {
	repo    port.UserRepository
	hasher  port.PasswordHasher
	authSvc port.AuthService
}

// NewLoginUseCase creates a LoginUseCase.
func NewLoginUseCase(
	repo port.UserRepository,
	hasher port.PasswordHasher,
	authSvc port.AuthService,
) *LoginUseCase {
	return &LoginUseCase{repo: repo, hasher: hasher, authSvc: authSvc}
}

// Execute authenticates a user and returns tokens.
func (uc *LoginUseCase) Execute(ctx context.Context, input LoginInput) (*AuthResponse, error) {
	email, err := domainUser.NewEmail(input.Email)
	if err != nil {
		return nil, domainUser.ErrInvalidCredentials
	}

	u, err := uc.repo.GetByEmail(ctx, string(email))
	if err != nil || u == nil {
		return nil, domainUser.ErrInvalidCredentials
	}

	if err := uc.hasher.Compare(u.PasswordHash, input.Password); err != nil {
		return nil, domainUser.ErrInvalidCredentials
	}

	tokens, err := uc.authSvc.IssueTokenPair(ctx, u.ID)
	if err != nil {
		return nil, err
	}

	return &AuthResponse{
		User:         FromUser(u),
		AccessToken:  tokens.AccessToken,
		RefreshToken: tokens.RefreshToken,
	}, nil
}

package user

import (
	"context"

	domainUser "github.com/nikitakovalevtaverz/chirp/internal/domain/user"
	"github.com/nikitakovalevtaverz/chirp/internal/port"
)

// GetProfileUseCase retrieves a user's profile by ID.
type GetProfileUseCase struct {
	repo port.UserRepository
}

// NewGetProfileUseCase creates a GetProfileUseCase.
func NewGetProfileUseCase(repo port.UserRepository) *GetProfileUseCase {
	return &GetProfileUseCase{repo: repo}
}

// Execute returns the user's profile.
func (uc *GetProfileUseCase) Execute(ctx context.Context, userID string) (*UserResponse, error) {
	u, err := uc.repo.GetByID(ctx, userID)
	if err != nil {
		return nil, err
	}
	if u == nil {
		return nil, domainUser.ErrUserNotFound
	}
	resp := FromUser(u)
	return &resp, nil
}

package user

import "github.com/google/uuid"

// newID generates a new unique identifier.
// In production, this would use UUID v7 from your database or a real UUID package.
func newID() string {
	return uuid.New().String()
}

