package middleware

import "context"

type ctxKey string

const UserIDKey ctxKey = "user_id"

// UserIDFromContext returns the authenticated user ID from context.
func UserIDFromContext(ctx context.Context) (string, bool) {
	id, ok := ctx.Value(UserIDKey).(string)
	return id, ok
}

package middleware

import (
	"context"
	"net/http"
	"strings"

	"github.com/nikitakovalevtaverz/chirp/internal/port"
	"github.com/nikitakovalevtaverz/chirp/pkg/api"
)

// AuthGuard is an HTTP middleware that validates JWT access tokens.
type AuthGuard struct {
	authSvc port.AuthService
}

// NewAuthGuard creates an AuthGuard.
func NewAuthGuard(authSvc port.AuthService) *AuthGuard {
	return &AuthGuard{authSvc: authSvc}
}

// Middleware returns an HTTP middleware handler.
func (g *AuthGuard) Middleware(next http.Handler) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		header := r.Header.Get("Authorization")
		if header == "" {
			api.Unauthorized(w, "missing authorization header")
			return
		}

		if !strings.HasPrefix(header, "Bearer ") {
			api.Unauthorized(w, "authorization header must be Bearer <token>")
			return
		}

		token := strings.TrimPrefix(header, "Bearer ")
		userID, err := g.authSvc.ValidateAccessToken(r.Context(), token)
		if err != nil {
			api.Unauthorized(w, "invalid or expired token")
			return
		}

		ctx := context.WithValue(r.Context(), UserIDKey, userID)
		next.ServeHTTP(w, r.WithContext(ctx))
	})
}

package transport

import (
	"errors"
	"net/http"

	domainUser "github.com/nikitakovalevtaverz/chirp/internal/domain/user"
	usecaseUser "github.com/nikitakovalevtaverz/chirp/internal/usecase/user"
	"github.com/nikitakovalevtaverz/chirp/pkg/api"
)

// RegisterRequest is the HTTP request body for registration.
type RegisterRequest struct {
	Username string `json:"username"`
	Email    string `json:"email"`
	Password string `json:"password"`
}

// LoginRequest is the HTTP request body for login.
type LoginRequest struct {
	Email    string `json:"email"`
	Password string `json:"password"`
}

// AuthHandler handles authentication endpoints.
type AuthHandler struct {
	register *usecaseUser.RegisterUseCase
	login    *usecaseUser.LoginUseCase
}

// NewAuthHandler creates an AuthHandler.
func NewAuthHandler(
	register *usecaseUser.RegisterUseCase,
	login *usecaseUser.LoginUseCase,
) *AuthHandler {
	return &AuthHandler{register: register, login: login}
}

// Register handles POST /api/v1/auth/register
//
//	@Summary		Register a new user
//	@Description	Creates a new account and returns JWT tokens.
//	@Tags			auth
//	@Accept			json
//	@Produce		json
//	@Param			body	body		RegisterRequest	true	"Registration payload"
//	@Success		201		{object}	usecaseUser.AuthResponse
//	@Failure		400		{object}	api.ProblemDetail
//	@Failure		409		{object}	api.ProblemDetail
//	@Router			/auth/register [post]
func (h *AuthHandler) Register(w http.ResponseWriter, r *http.Request) {
	var req RegisterRequest
	if err := api.Decode(w, r, &req); err != nil {
		return
	}

	input := usecaseUser.RegisterInput{
		Username: req.Username,
		Email:    req.Email,
		Password: req.Password,
	}

	resp, err := h.register.Execute(r.Context(), input)
	if err != nil {
		mapAuthError(w, err)
		return
	}

	api.RespondCreated(w, resp)
}

// Login handles POST /api/v1/auth/login
//
//	@Summary		Login
//	@Description	Authenticates a user and returns JWT tokens.
//	@Tags			auth
//	@Accept			json
//	@Produce		json
//	@Param			body	body		LoginRequest	true	"Login payload"
//	@Success		200		{object}	usecaseUser.AuthResponse
//	@Failure		400		{object}	api.ProblemDetail
//	@Failure		401		{object}	api.ProblemDetail
//	@Router			/auth/login [post]
func (h *AuthHandler) Login(w http.ResponseWriter, r *http.Request) {
	var req LoginRequest
	if err := api.Decode(w, r, &req); err != nil {
		return
	}

	input := usecaseUser.LoginInput{
		Email:    req.Email,
		Password: req.Password,
	}

	resp, err := h.login.Execute(r.Context(), input)
	if err != nil {
		mapAuthError(w, err)
		return
	}

	api.RespondOK(w, resp)
}

// mapAuthError maps domain errors to HTTP responses.
func mapAuthError(w http.ResponseWriter, err error) {
	switch {
	case errors.Is(err, domainUser.ErrEmailTaken):
		api.Conflict(w, "email already registered")
	case errors.Is(err, domainUser.ErrUsernameTaken):
		api.Conflict(w, "username already taken")
	case errors.Is(err, domainUser.ErrInvalidCredentials):
		api.Unauthorized(w, "invalid email or password")
	case isValidationError(err):
		api.BadRequest(w, err.Error())
	default:
		api.InternalError(w, "internal server error")
	}
}

func isValidationError(err error) bool {
	return errors.Is(err, domainUser.ErrUsernameTooShort) ||
		errors.Is(err, domainUser.ErrUsernameTooLong) ||
		errors.Is(err, domainUser.ErrUsernameInvalid) ||
		errors.Is(err, domainUser.ErrEmailEmpty) ||
		errors.Is(err, domainUser.ErrEmailInvalid) ||
		errors.Is(err, domainUser.ErrPasswordTooShort) ||
		errors.Is(err, domainUser.ErrPasswordTooLong)
}

package transport

import (
	"errors"
	"net/http"

	domainUser "github.com/nikitakovalevtaverz/chirp/internal/domain/user"
	usecaseUser "github.com/nikitakovalevtaverz/chirp/internal/usecase/user"
	"github.com/nikitakovalevtaverz/chirp/internal/transport/middleware"
	"github.com/nikitakovalevtaverz/chirp/pkg/api"
)

// UserHandler handles user profile endpoints.
type UserHandler struct {
	getProfile *usecaseUser.GetProfileUseCase
}

// NewUserHandler creates a UserHandler.
func NewUserHandler(getProfile *usecaseUser.GetProfileUseCase) *UserHandler {
	return &UserHandler{getProfile: getProfile}
}

// Me handles GET /api/v1/users/me
//
//	@Summary		Get current user profile
//	@Description	Returns the authenticated user's profile.
//	@Tags			users
//	@Produce		json
//	@Security		BearerAuth
//	@Success		200	{object}	usecaseUser.UserResponse
//	@Failure		401	{object}	api.ProblemDetail
//	@Router			/users/me [get]
func (h *UserHandler) Me(w http.ResponseWriter, r *http.Request) {
	userID, ok := middleware.UserIDFromContext(r.Context())
	if !ok {
		api.Unauthorized(w, "not authenticated")
		return
	}

	resp, err := h.getProfile.Execute(r.Context(), userID)
	if err != nil {
		if errors.Is(err, domainUser.ErrUserNotFound) {
			api.NotFound(w, "user not found")
			return
		}
		api.InternalError(w, "internal server error")
		return
	}

	api.RespondOK(w, resp)
}

package config

import (
	"os"

	"github.com/nikitakovalevtaverz/chirp/internal/adapter/memory"
)

// Config holds all configuration for the application.
type Config struct {
	HTTPPort string
	AppEnv   string

	// JWT secrets (hex-encoded)
	AccessTokenSecret  string
	RefreshTokenSecret string
}

// Load reads configuration from environment variables with sensible defaults.
func Load() (*Config, error) {
	accessSecret := getEnv("JWT_ACCESS_SECRET", "")
	refreshSecret := getEnv("JWT_REFRESH_SECRET", "")

	// Auto-generate secrets in development
	if accessSecret == "" && getEnv("APP_ENV", "development") == "development" {
		var err error
		accessSecret, err = memory.GenerateSecret()
		if err != nil {
			return nil, err
		}
		refreshSecret, err = memory.GenerateSecret()
		if err != nil {
			return nil, err
		}
	}

	return &Config{
		HTTPPort:           getEnv("HTTP_PORT", "8080"),
		AppEnv:             getEnv("APP_ENV", "development"),
		AccessTokenSecret:  accessSecret,
		RefreshTokenSecret: refreshSecret,
	}, nil
}

func getEnv(key, fallback string) string {
	if v := os.Getenv(key); v != "" {
		return v
	}
	return fallback
}

package app

import (
	"context"
	"net/http"

	"github.com/go-chi/chi/v5"
	"github.com/go-chi/chi/v5/middleware"
	httpSwagger "github.com/swaggo/http-swagger"

	"github.com/nikitakovalevtaverz/chirp/internal/adapter/memory"
	"github.com/nikitakovalevtaverz/chirp/internal/config"
	"github.com/nikitakovalevtaverz/chirp/internal/port"
	"github.com/nikitakovalevtaverz/chirp/internal/transport"
	"github.com/nikitakovalevtaverz/chirp/internal/transport/middleware"
	usecaseUser "github.com/nikitakovalevtaverz/chirp/internal/usecase/user"
	"github.com/nikitakovalevtaverz/chirp/pkg/api"
)

// App is the main application struct that holds the HTTP server
// and all dependencies.
type App struct {
	server *http.Server
}

// New creates a new App with all dependencies wired up.
func New(cfg *config.Config) (*App, error) {
	// --- Adapters ---
	userRepo := memory.NewUserRepo()
	passwordHasher := memory.NewPasswordHasher(10)
	authSvc, err := memory.NewAuthService(cfg.AccessTokenSecret, cfg.RefreshTokenSecret)
	if err != nil {
		return nil, err
	}

	// --- Use Cases ---
	registerUC := usecaseUser.NewRegisterUseCase(userRepo, passwordHasher, authSvc)
	loginUC := usecaseUser.NewLoginUseCase(userRepo, passwordHasher, authSvc)
	getProfileUC := usecaseUser.NewGetProfileUseCase(userRepo)

	// --- Transport ---
	authHandler := transport.NewAuthHandler(registerUC, loginUC)
	userHandler := transport.NewUserHandler(getProfileUC)

	// --- Middleware ---
	authGuard := middleware.NewAuthGuard(authSvc)

	// --- Router ---
	r := chi.NewRouter()
	r.Use(middleware.Logger)
	r.Use(middleware.Recoverer)
	r.Use(middleware.RequestID)
	r.Use(middleware.RealIP)

	// API v1
	r.Route("/api/v1", func(r chi.Router) {
		// Public
		r.Get("/health", healthHandler)
		r.Get("/hello", helloHandler)

		r.Route("/auth", func(r chi.Router) {
			r.Post("/register", authHandler.Register)
			r.Post("/login", authHandler.Login)
		})

		// Protected
		r.Group(func(r chi.Router) {
			r.Use(authGuard.Middleware)
			r.Get("/users/me", userHandler.Me)
		})
	})

	// Swagger UI
	r.Get("/swagger/*", httpSwagger.Handler(
		httpSwagger.URL("/swagger/doc.json"),
	))

	return &App{
		server: &http.Server{
			Addr:    ":" + cfg.HTTPPort,
			Handler: r,
		},
	}, nil
}

// ListenAndServe starts the HTTP server.
func (a *App) ListenAndServe() error {
	return a.server.ListenAndServe()
}

// Shutdown gracefully shuts down the HTTP server.
func (a *App) Shutdown(ctx context.Context) error {
	return a.server.Shutdown(ctx)
}

// healthHandler responds with service status.
//
//	@Summary		Health check
//	@Description	Returns service health status.
//	@Tags			system
//	@Produce		plain
//	@Success		200	{string}	string	"ok"
//	@Router			/health [get]
func healthHandler(w http.ResponseWriter, r *http.Request) {
	w.Header().Set("Content-Type", "text/plain")
	w.WriteHeader(http.StatusOK)
	w.Write([]byte("ok"))
}

// helloHandler responds with a greeting.
//
//	@Summary		Hello world
//	@Description	Returns a hello world JSON message.
//	@Tags			system
//	@Produce		json
//	@Success		200	{object}	map[string]string
//	@Router			/hello [get]
func helloHandler(w http.ResponseWriter, r *http.Request) {
	api.RespondOK(w, map[string]string{"message": "hello world"})
}

