// Package tweet contains the tweet domain model.
package tweet

import "time"

// Tweet represents a single post.
type Tweet struct {
	ID        string
	AuthorID  string
	Body      string
	ParentID  string // empty if root tweet, otherwise ID of parent
	CreatedAt time.Time
	UpdatedAt time.Time
}

package tweet

import "errors"

// Domain errors.
var (
	ErrTweetNotFound = errors.New("tweet not found")
	ErrBodyTooLong   = errors.New("tweet body: must be at most 280 characters")
	ErrBodyEmpty     = errors.New("tweet body: must not be empty")
	ErrNotOwner      = errors.New("not the owner of this tweet")
)

// Body validates a tweet body.
type Body string

// NewBody creates a validated Body.
func NewBody(raw string) (Body, error) {
	switch {
	case raw == "":
		return "", ErrBodyEmpty
	case len([]rune(raw)) > 280:
		return "", ErrBodyTooLong
	}
	return Body(raw), nil
}

