package port

import (
	"context"

	"github.com/nikitakovalevtaverz/chirp/internal/domain/tweet"
)

// TweetRepository is the persistence port for tweets.
type TweetRepository interface {
	Create(ctx context.Context, t *tweet.Tweet) error
	GetByID(ctx context.Context, id string) (*tweet.Tweet, error)
	ListByAuthor(ctx context.Context, authorID string, limit int, cursor string) ([]*tweet.Tweet, string, error)
	Delete(ctx context.Context, id string) error
}

package tweet

import (
	"context"
	"fmt"

	"github.com/google/uuid"
	domainTweet "github.com/nikitakovalevtaverz/chirp/internal/domain/tweet"
	"github.com/nikitakovalevtaverz/chirp/internal/port"
)

// CreateUseCase handles tweet creation.
type CreateUseCase struct {
	repo port.TweetRepository
}

// NewCreateUseCase creates a CreateUseCase.
func NewCreateUseCase(repo port.TweetRepository) *CreateUseCase {
	return &CreateUseCase{repo: repo}
}

// CreateInput is the DTO for creating a tweet.
type CreateInput struct {
	Body     string
	AuthorID string
	ParentID string // optional
}

// Execute creates a new tweet.
func (uc *CreateUseCase) Execute(ctx context.Context, input CreateInput) (*domainTweet.Tweet, error) {
	body, err := domainTweet.NewBody(input.Body)
	if err != nil {
		return nil, err
	}
	if input.ParentID != "" {
		parent, _ := uc.repo.GetByID(ctx, input.ParentID)
		if parent == nil {
			return nil, fmt.Errorf("parent tweet not found")
		}
	}

	t := &domainTweet.Tweet{
		ID:       uuid.New().String(),
		AuthorID: input.AuthorID,
		Body:     string(body),
		ParentID: input.ParentID,
	}

	if err := uc.repo.Create(ctx, t); err != nil {
		return nil, err
	}
	return t, nil
}

package tweet

import (
	"context"

	domainTweet "github.com/nikitakovalevtaverz/chirp/internal/domain/tweet"
	"github.com/nikitakovalevtaverz/chirp/internal/port"
)

// GetByIDUseCase retrieves a tweet by ID.
type GetByIDUseCase struct {
	repo port.TweetRepository
}

// NewGetByIDUseCase creates a GetByIDUseCase.
func NewGetByIDUseCase(repo port.TweetRepository) *GetByIDUseCase {
	return &GetByIDUseCase{repo: repo}
}

// Execute returns the tweet or an error.
func (uc *GetByIDUseCase) Execute(ctx context.Context, id string) (*domainTweet.Tweet, error) {
	t, err := uc.repo.GetByID(ctx, id)
	if err != nil {
		return nil, err
	}
	if t == nil {
		return nil, domainTweet.ErrTweetNotFound
	}
	return t, nil
}

package tweet

import (
	"context"

	domainTweet "github.com/nikitakovalevtaverz/chirp/internal/domain/tweet"
	"github.com/nikitakovalevtaverz/chirp/internal/port"
)

// ListByUserUseCase lists tweets by author.
type ListByUserUseCase struct {
	repo port.TweetRepository
}

// NewListByUserUseCase creates a ListByUserUseCase.
func NewListByUserUseCase(repo port.TweetRepository) *ListByUserUseCase {
	return &ListByUserUseCase{repo: repo}
}

// ListInput is the DTO for listing tweets.
type ListInput struct {
	AuthorID string
	Limit    int
	Cursor   string
}

// Execute returns a paginated list.
func (uc *ListByUserUseCase) Execute(ctx context.Context, input ListInput) ([]*domainTweet.Tweet, string, error) {
	return uc.repo.ListByAuthor(ctx, input.AuthorID, input.Limit, input.Cursor)
}

package tweet

import (
	"context"

	domainTweet "github.com/nikitakovalevtaverz/chirp/internal/domain/tweet"
	"github.com/nikitakovalevtaverz/chirp/internal/port"
)

// DeleteUseCase handles tweet deletion.
type DeleteUseCase struct {
	repo port.TweetRepository
}

// NewDeleteUseCase creates a DeleteUseCase.
func NewDeleteUseCase(repo port.TweetRepository) *DeleteUseCase {
	return &DeleteUseCase{repo: repo}
}

// Execute deletes a tweet if the requester is the owner.
func (uc *DeleteUseCase) Execute(ctx context.Context, id, requesterID string) error {
	t, err := uc.repo.GetByID(ctx, id)
	if err != nil {
		return err
	}
	if t == nil {
		return domainTweet.ErrTweetNotFound
	}
	if t.AuthorID != requesterID {
		return domainTweet.ErrNotOwner
	}
	return uc.repo.Delete(ctx, id)
}

package memory

import (
	"context"
	"sort"
	"sync"

	"github.com/nikitakovalevtaverz/chirp/internal/domain/tweet"
)

// TweetRepo is an in-memory implementation of port.TweetRepository.
type TweetRepo struct {
	mu     sync.RWMutex
	tweets map[string]*tweet.Tweet
	byUser map[string][]string // authorID -> tweetIDs
}

// NewTweetRepo creates an empty TweetRepo.
func NewTweetRepo() *TweetRepo {
	return &TweetRepo{
		tweets: make(map[string]*tweet.Tweet),
		byUser: make(map[string][]string),
	}
}

func (r *TweetRepo) Create(_ context.Context, t *tweet.Tweet) error {
	r.mu.Lock()
	defer r.mu.Unlock()
	r.tweets[t.ID] = t
	r.byUser[t.AuthorID] = append(r.byUser[t.AuthorID], t.ID)
	return nil
}

func (r *TweetRepo) GetByID(_ context.Context, id string) (*tweet.Tweet, error) {
	r.mu.RLock()
	defer r.mu.RUnlock()
	return r.tweets[id], nil
}

func (r *TweetRepo) ListByAuthor(_ context.Context, authorID string, limit int, cursor string) ([]*tweet.Tweet, string, error) {
	r.mu.RLock()
	defer r.mu.RUnlock()

	ids := r.byUser[authorID]
	if limit <= 0 || limit > 50 {
		limit = 20
	}

	// Sort by insertion order (ID acts as cursor)
	sort.Strings(ids)

	start := 0
	if cursor != "" {
		for i, id := range ids {
			if id == cursor {
				start = i + 1
				break
			}
		}
	}

	end := start + limit
	if end > len(ids) {
		end = len(ids)
	}

	var result []*tweet.Tweet
	for _, id := range ids[start:end] {
		result = append(result, r.tweets[id])
	}

	nextCursor := ""
	if end < len(ids) {
		nextCursor = ids[end]
	}

	return result, nextCursor, nil
}

func (r *TweetRepo) Delete(_ context.Context, id string) error {
	r.mu.Lock()
	defer r.mu.Unlock()
	delete(r.tweets, id)
	return nil
}

