package postgres

import (
	"context"
	"fmt"
	"log/slog"

	"github.com/jackc/pgx/v5/pgxpool"
)

// Pool wraps a pgx connection pool.
type Pool struct {
	*pgxpool.Pool
}

// NewPool creates a new pgxpool.Pool.
func NewPool(ctx context.Context, dsn string) (*Pool, error) {
	cfg, err := pgxpool.ParseConfig(dsn)
	if err != nil {
		return nil, fmt.Errorf("parse dsn: %w", err)
	}

	cfg.MaxConns = 20
	cfg.MinConns = 2

	pool, err := pgxpool.NewWithConfig(ctx, cfg)
	if err != nil {
		return nil, fmt.Errorf("create pool: %w", err)
	}

	if err := pool.Ping(ctx); err != nil {
		pool.Close()
		return nil, fmt.Errorf("ping: %w", err)
	}

	slog.Info("connected to PostgreSQL")
	return &Pool{Pool: pool}, nil
}

// Close closes the pool.
func (p *Pool) Close() {
	p.Pool.Close()
}

package postgres

import (
	"context"
	"time"

	"github.com/nikitakovalevtaverz/chirp/internal/domain/user"
)

// UserRepo implements port.UserRepository with PostgreSQL.
type UserRepo struct {
	pool *Pool
}

// NewUserRepo creates a UserRepo.
func NewUserRepo(pool *Pool) *UserRepo {
	return &UserRepo{pool: pool}
}

func (r *UserRepo) Create(ctx context.Context, u *user.User) error {
	const q = `INSERT INTO users (id, username, email, password_hash, display_name, bio, created_at, updated_at)
		VALUES ($1, $2, $3, $4, $5, $6, $7, $8)`
	now := time.Now().UTC()
	u.CreatedAt = now
	u.UpdatedAt = now
	_, err := r.pool.Exec(ctx, q,
		u.ID, u.Username, u.Email, u.PasswordHash,
		u.DisplayName, u.Bio, u.CreatedAt, u.UpdatedAt,
	)
	return err
}

func (r *UserRepo) GetByID(ctx context.Context, id string) (*user.User, error) {
	const q = `SELECT id, username, email, password_hash, display_name, bio, created_at, updated_at
		FROM users WHERE id = $1`
	var u user.User
	err := r.pool.QueryRow(ctx, q, id).Scan(
		&u.ID, &u.Username, &u.Email, &u.PasswordHash,
		&u.DisplayName, &u.Bio, &u.CreatedAt, &u.UpdatedAt,
	)
	if err != nil {
		if isNoRows(err) {
			return nil, nil
		}
		return nil, err
	}
	return &u, nil
}

func (r *UserRepo) GetByEmail(ctx context.Context, email string) (*user.User, error) {
	const q = `SELECT id, username, email, password_hash, display_name, bio, created_at, updated_at
		FROM users WHERE email = $1`
	var u user.User
	err := r.pool.QueryRow(ctx, q, email).Scan(
		&u.ID, &u.Username, &u.Email, &u.PasswordHash,
		&u.DisplayName, &u.Bio, &u.CreatedAt, &u.UpdatedAt,
	)
	if err != nil {
		if isNoRows(err) {
			return nil, nil
		}
		return nil, err
	}
	return &u, nil
}

func (r *UserRepo) GetByUsername(ctx context.Context, username string) (*user.User, error) {
	const q = `SELECT id, username, email, password_hash, display_name, bio, created_at, updated_at
		FROM users WHERE username = $1`
	var u user.User
	err := r.pool.QueryRow(ctx, q, username).Scan(
		&u.ID, &u.Username, &u.Email, &u.PasswordHash,
		&u.DisplayName, &u.Bio, &u.CreatedAt, &u.UpdatedAt,
	)
	if err != nil {
		if isNoRows(err) {
			return nil, nil
		}
		return nil, err
	}
	return &u, nil
}

func isNoRows(err error) bool {
	return err != nil && err.Error() == "no rows in result set"
}

package postgres

import (
	"context"
	"time"

	"github.com/nikitakovalevtaverz/chirp/internal/domain/tweet"
)

// TweetRepo implements port.TweetRepository with PostgreSQL.
type TweetRepo struct {
	pool *Pool
}

// NewTweetRepo creates a TweetRepo.
func NewTweetRepo(pool *Pool) *TweetRepo {
	return &TweetRepo{pool: pool}
}

func (r *TweetRepo) Create(ctx context.Context, t *tweet.Tweet) error {
	const q = `INSERT INTO tweets (id, author_id, body, parent_id, created_at, updated_at)
		VALUES ($1, $2, $3, NULLIF($4, ''), $5, $6)`
	now := time.Now().UTC()
	t.CreatedAt = now
	t.UpdatedAt = now
	_, err := r.pool.Exec(ctx, q,
		t.ID, t.AuthorID, t.Body, t.ParentID, t.CreatedAt, t.UpdatedAt,
	)
	return err
}

func (r *TweetRepo) GetByID(ctx context.Context, id string) (*tweet.Tweet, error) {
	const q = `SELECT id, author_id, body, COALESCE(parent_id, ''), created_at, updated_at
		FROM tweets WHERE id = $1`
	var t tweet.Tweet
	err := r.pool.QueryRow(ctx, q, id).Scan(
		&t.ID, &t.AuthorID, &t.Body, &t.ParentID, &t.CreatedAt, &t.UpdatedAt,
	)
	if err != nil {
		if isNoRows(err) {
			return nil, nil
		}
		return nil, err
	}
	return &t, nil
}

func (r *TweetRepo) ListByAuthor(ctx context.Context, authorID string, limit int, cursor string) ([]*tweet.Tweet, string, error) {
	if limit <= 0 || limit > 50 {
		limit = 20
	}

	var rows interface{ Close() }
	var err error
	if cursor == "" {
		const q = `SELECT id, author_id, body, COALESCE(parent_id, ''), created_at, updated_at
			FROM tweets WHERE author_id = $1 ORDER BY created_at DESC, id DESC LIMIT $2`
		rows, err = r.pool.Query(ctx, q, authorID, limit+1)
	} else {
		const q = `SELECT id, author_id, body, COALESCE(parent_id, ''), created_at, updated_at
			FROM tweets WHERE author_id = $1 AND (created_at, id) < (
				SELECT created_at, id FROM tweets WHERE id = $2
			) ORDER BY created_at DESC, id DESC LIMIT $3`
		rows, err = r.pool.Query(ctx, q, authorID, cursor, limit+1)
	}
	if err != nil {
		return nil, "", err
	}
	defer rows.Close()

	var tweets []*tweet.Tweet
	for rows.Next() {
		var t tweet.Tweet
		if err := rows.Scan(&t.ID, &t.AuthorID, &t.Body, &t.ParentID, &t.CreatedAt, &t.UpdatedAt); err != nil {
			return nil, "", err
		}
		tweets = append(tweets, &t)
	}

	nextCursor := ""
	if len(tweets) > limit {
		nextCursor = tweets[limit-1].ID
		tweets = tweets[:limit]
	}

	return tweets, nextCursor, nil
}

func (r *TweetRepo) Delete(ctx context.Context, id string) error {
	const q = `DELETE FROM tweets WHERE id = $1`
	_, err := r.pool.Exec(ctx, q, id)
	return err
}

package redis

import (
	"context"
	"fmt"
	"log/slog"

	goredis "github.com/redis/go-redis/v9"
)

// Client wraps a Redis client.
type Client struct {
	*goredis.Client
}

// NewClient creates a new Redis client.
func NewClient(ctx context.Context, addr, password string, db int) (*Client, error) {
	rdb := goredis.NewClient(&goredis.Options{
		Addr:     addr,
		Password: password,
		DB:       db,
	})

	if err := rdb.Ping(ctx).Err(); err != nil {
		return nil, fmt.Errorf("redis ping: %w", err)
	}

	slog.Info("connected to Redis")
	return &Client{Client: rdb}, nil
}

-- +goose Up
CREATE EXTENSION IF NOT EXISTS "pgcrypto";

CREATE TABLE users (
    id          UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    username    VARCHAR(30)  NOT NULL UNIQUE,
    email       VARCHAR(255) NOT NULL UNIQUE,
    password_hash TEXT       NOT NULL,
    display_name VARCHAR(100) NOT NULL DEFAULT '',
    bio         TEXT         NOT NULL DEFAULT '',
    created_at  TIMESTAMPTZ  NOT NULL DEFAULT now(),
    updated_at  TIMESTAMPTZ  NOT NULL DEFAULT now()
);

CREATE INDEX idx_users_email ON users(email);
CREATE INDEX idx_users_username ON users(username);

-- +goose Down
DROP TABLE IF EXISTS users;

-- +goose Up
