package config

import (
	"os"

	"github.com/nikitakovalevtaverz/chirp/internal/adapter/memory"
)

// Config holds all configuration for the application.
type Config struct {
	HTTPPort string
	AppEnv   string

	// PostgreSQL
	DatabaseURL string

	// Redis
	RedisURL string

	// JWT secrets (hex-encoded)
	AccessTokenSecret  string
	RefreshTokenSecret string
}

// Load reads configuration from environment variables with sensible defaults.
func Load() (*Config, error) {
	accessSecret := getEnv("JWT_ACCESS_SECRET", "")
	refreshSecret := getEnv("JWT_REFRESH_SECRET", "")

	// Auto-generate secrets in development
	if accessSecret == "" && getEnv("APP_ENV", "development") == "development" {
		var err error
		accessSecret, err = memory.GenerateSecret()
		if err != nil {
			return nil, err
		}
		refreshSecret, err = memory.GenerateSecret()
		if err != nil {
			return nil, err
		}
	}

	return &Config{
		HTTPPort:           getEnv("HTTP_PORT", "8080"),
		AppEnv:             getEnv("APP_ENV", "development"),
		DatabaseURL:        getEnv("DATABASE_URL", ""),
		RedisURL:           getEnv("REDIS_URL", ""),
		AccessTokenSecret:  accessSecret,
		RefreshTokenSecret: refreshSecret,
	}, nil
}

func getEnv(key, fallback string) string {
	if v := os.Getenv(key); v != "" {
		return v
	}
	return fallback
}

package app

import (
	"context"
	"log/slog"
	"net/http"

	"github.com/go-chi/chi/v5"
	"github.com/go-chi/chi/v5/middleware"
	httpSwagger "github.com/swaggo/http-swagger"

	"github.com/nikitakovalevtaverz/chirp/internal/adapter/memory"
	"github.com/nikitakovalevtaverz/chirp/internal/adapter/postgres"
	"github.com/nikitakovalevtaverz/chirp/internal/adapter/redis"
	"github.com/nikitakovalevtaverz/chirp/internal/config"
	"github.com/nikitakovalevtaverz/chirp/internal/port"
	"github.com/nikitakovalevtaverz/chirp/internal/transport"
	appmw "github.com/nikitakovalevtaverz/chirp/internal/transport/middleware"
	usecaseTweet "github.com/nikitakovalevtaverz/chirp/internal/usecase/tweet"
	usecaseUser "github.com/nikitakovalevtaverz/chirp/internal/usecase/user"
	"github.com/nikitakovalevtaverz/chirp/pkg/api"
)

// App is the main application struct that holds the HTTP server
// and all dependencies.
type App struct {
	server   *http.Server
	pgPool   *postgres.Pool
	redisCli *redis.Client
}

// New creates a new App with all dependencies wired up.
func New(cfg *config.Config) (*App, error) {
	// --- Adapters (PG or memory) ---
	var (
		userRepo  port.UserRepository
		tweetRepo port.TweetRepository
		pgPool    *postgres.Pool
	)

	if cfg.DatabaseURL != "" {
		var err error
		pgPool, err = postgres.NewPool(context.Background(), cfg.DatabaseURL)
		if err != nil {
			return nil, err
		}
		userRepo = postgres.NewUserRepo(pgPool)
		tweetRepo = postgres.NewTweetRepo(pgPool)
	} else {
		slog.Warn("DATABASE_URL not set — using in-memory storage (data lost on restart)")
		userRepo = memory.NewUserRepo()
		tweetRepo = memory.NewTweetRepo()
	}

	// --- Redis (optional) ---
	var redisCli *redis.Client
	if cfg.RedisURL != "" {
		var err error
		redisCli, err = redis.NewClient(context.Background(), cfg.RedisURL, "", 0)
		if err != nil {
			slog.Warn("failed to connect to Redis, continuing without it", "error", err)
		}
	} else {
		slog.Warn("REDIS_URL not set — Redis disabled")
	}

	// --- Adapters ---
	passwordHasher := memory.NewPasswordHasher(10)
	authSvc, err := memory.NewAuthService(cfg.AccessTokenSecret, cfg.RefreshTokenSecret)
	if err != nil {
		return nil, err
	}

	// --- Use Cases ---
	registerUC := usecaseUser.NewRegisterUseCase(userRepo, passwordHasher, authSvc)
	loginUC := usecaseUser.NewLoginUseCase(userRepo, passwordHasher, authSvc)
	getProfileUC := usecaseUser.NewGetProfileUseCase(userRepo)

	createTweetUC := usecaseTweet.NewCreateUseCase(tweetRepo)
	getTweetUC := usecaseTweet.NewGetByIDUseCase(tweetRepo)
	listTweetsUC := usecaseTweet.NewListByUserUseCase(tweetRepo)
	deleteTweetUC := usecaseTweet.NewDeleteUseCase(tweetRepo)

	// --- Transport ---
	authHandler := transport.NewAuthHandler(registerUC, loginUC)
	userHandler := transport.NewUserHandler(getProfileUC)
	tweetHandler := transport.NewTweetHandler(createTweetUC, getTweetUC, listTweetsUC, deleteTweetUC)

	// --- Middleware ---
	authGuard := appmw.NewAuthGuard(authSvc)

	// --- Router ---
	r := chi.NewRouter()
	r.Use(middleware.Logger)
	r.Use(middleware.Recoverer)
	r.Use(middleware.RequestID)
	r.Use(middleware.RealIP)

	// API v1
	r.Route("/api/v1", func(r chi.Router) {
		r.Get("/health", healthHandler)
		r.Get("/hello", helloHandler)

		r.Route("/auth", func(r chi.Router) {
			r.Post("/register", authHandler.Register)
			r.Post("/login", authHandler.Login)
		})

		r.Get("/tweets/{id}", tweetHandler.Get)
		r.Get("/users/{id}/tweets", tweetHandler.ListByUser)

		r.Group(func(r chi.Router) {
			r.Use(authGuard.Middleware)
			r.Get("/users/me", userHandler.Me)
			r.Post("/tweets", tweetHandler.Create)
			r.Delete("/tweets/{id}", tweetHandler.Delete)
		})
	})

	r.Get("/swagger/*", httpSwagger.Handler(
		httpSwagger.URL("/swagger/doc.json"),
	))

	return &App{
		server: &http.Server{
			Addr:    ":" + cfg.HTTPPort,
			Handler: r,
		},
		pgPool:   pgPool,
		redisCli: redisCli,
	}, nil
}

func (a *App) ListenAndServe() error {
	return a.server.ListenAndServe()
}

func (a *App) Shutdown(ctx context.Context) error {
	if a.redisCli != nil {
		a.redisCli.Close()
	}
	if a.pgPool != nil {
		a.pgPool.Close()
	}
	return a.server.Shutdown(ctx)
}

func healthHandler(w http.ResponseWriter, r *http.Request) {
	w.Header().Set("Content-Type", "text/plain")
	w.WriteHeader(http.StatusOK)
	w.Write([]byte("ok"))
}

func helloHandler(w http.ResponseWriter, r *http.Request) {
	api.RespondOK(w, map[string]string{"message": "hello world"})
}

package postgres

import (
	"context"
	"time"

	"github.com/jackc/pgx/v5"
	"github.com/nikitakovalevtaverz/chirp/internal/domain/tweet"
)

// TweetRepo implements port.TweetRepository with PostgreSQL.
type TweetRepo struct {
	pool *Pool
}

// NewTweetRepo creates a TweetRepo.
func NewTweetRepo(pool *Pool) *TweetRepo {
	return &TweetRepo{pool: pool}
}

func (r *TweetRepo) Create(ctx context.Context, t *tweet.Tweet) error {
	const q = `INSERT INTO tweets (id, author_id, body, parent_id, created_at, updated_at)
		VALUES ($1, $2, $3, NULLIF($4, ''), $5, $6)`
	now := time.Now().UTC()
	t.CreatedAt = now
	t.UpdatedAt = now
	_, err := r.pool.Exec(ctx, q,
		t.ID, t.AuthorID, t.Body, t.ParentID, t.CreatedAt, t.UpdatedAt,
	)
	return err
}

func (r *TweetRepo) GetByID(ctx context.Context, id string) (*tweet.Tweet, error) {
	const q = `SELECT id, author_id, body, COALESCE(parent_id, ''), created_at, updated_at
		FROM tweets WHERE id = $1`
	var t tweet.Tweet
	err := r.pool.QueryRow(ctx, q, id).Scan(
		&t.ID, &t.AuthorID, &t.Body, &t.ParentID, &t.CreatedAt, &t.UpdatedAt,
	)
	if err != nil {
		if isNoRows(err) {
			return nil, nil
		}
		return nil, err
	}
	return &t, nil
}

func (r *TweetRepo) ListByAuthor(ctx context.Context, authorID string, limit int, cursor string) ([]*tweet.Tweet, string, error) {
	if limit <= 0 || limit > 50 {
		limit = 20
	}

	var rows pgx.Rows
	var err error
	if cursor == "" {
		const q = `SELECT id, author_id, body, COALESCE(parent_id, ''), created_at, updated_at
			FROM tweets WHERE author_id = $1 ORDER BY created_at DESC, id DESC LIMIT $2`
		rows, err = r.pool.Query(ctx, q, authorID, limit+1)
	} else {
		const q = `SELECT id, author_id, body, COALESCE(parent_id, ''), created_at, updated_at
			FROM tweets WHERE author_id = $1 AND (created_at, id) < (
				SELECT created_at, id FROM tweets WHERE id = $2
			) ORDER BY created_at DESC, id DESC LIMIT $3`
		rows, err = r.pool.Query(ctx, q, authorID, cursor, limit+1)
	}
	if err != nil {
		return nil, "", err
	}
	defer rows.Close()

	var tweets []*tweet.Tweet
	for rows.Next() {
		var t tweet.Tweet
		if err := rows.Scan(&t.ID, &t.AuthorID, &t.Body, &t.ParentID, &t.CreatedAt, &t.UpdatedAt); err != nil {
			return nil, "", err
		}
		tweets = append(tweets, &t)
	}

	nextCursor := ""
	if len(tweets) > limit {
		nextCursor = tweets[limit-1].ID
		tweets = tweets[:limit]
	}

	return tweets, nextCursor, nil
}

func (r *TweetRepo) Delete(ctx context.Context, id string) error {
	const q = `DELETE FROM tweets WHERE id = $1`
	_, err := r.pool.Exec(ctx, q, id)
	return err
}

