package timeline

import "time"

// Follow represents a user following another user.
type Follow struct {
	FollowerID string
	FolloweeID string
	CreatedAt  time.Time
}

package port

import (
	"context"

	"github.com/nikitakovalevtaverz/chirp/internal/domain/timeline"
)

// FollowRepository is the persistence port for follows.
type FollowRepository interface {
	Follow(ctx context.Context, followerID, followeeID string) error
	Unfollow(ctx context.Context, followerID, followeeID string) error
	IsFollowing(ctx context.Context, followerID, followeeID string) (bool, error)
	ListFollowers(ctx context.Context, userID string, limit int, cursor string) ([]*timeline.Follow, string, error)
	ListFollowing(ctx context.Context, userID string, limit int, cursor string) ([]*timeline.Follow, string, error)
	CountFollowers(ctx context.Context, userID string) (int, error)
	CountFollowing(ctx context.Context, userID string) (int, error)
}

package timeline

import (
	"context"

	"github.com/nikitakovalevtaverz/chirp/internal/port"
)

// FollowUseCase handles following a user.
type FollowUseCase struct {
	repo port.FollowRepository
}

// NewFollowUseCase creates a FollowUseCase.
func NewFollowUseCase(repo port.FollowRepository) *FollowUseCase {
	return &FollowUseCase{repo: repo}
}

// Execute follows a user. Returns nil if already following.
func (uc *FollowUseCase) Execute(ctx context.Context, followerID, followeeID string) error {
	if followerID == followeeID {
		return ErrCannotFollowSelf
	}
	return uc.repo.Follow(ctx, followerID, followeeID)
}

package timeline

import (
	"context"

	"github.com/nikitakovalevtaverz/chirp/internal/port"
)

// UnfollowUseCase handles unfollowing a user.
type UnfollowUseCase struct {
	repo port.FollowRepository
}

// NewUnfollowUseCase creates an UnfollowUseCase.
func NewUnfollowUseCase(repo port.FollowRepository) *UnfollowUseCase {
	return &UnfollowUseCase{repo: repo}
}

// Execute unfollows a user.
func (uc *UnfollowUseCase) Execute(ctx context.Context, followerID, followeeID string) error {
	return uc.repo.Unfollow(ctx, followerID, followeeID)
}

package timeline

import "errors"

var (
	ErrCannotFollowSelf = errors.New("cannot follow yourself")
)

package timeline

import (
	"context"

	domainTL "github.com/nikitakovalevtaverz/chirp/internal/domain/timeline"
	"github.com/nikitakovalevtaverz/chirp/internal/port"
)

// ListFollowersUseCase lists followers of a user.
type ListFollowersUseCase struct {
	repo port.FollowRepository
}

// NewListFollowersUseCase creates a ListFollowersUseCase.
func NewListFollowersUseCase(repo port.FollowRepository) *ListFollowersUseCase {
	return &ListFollowersUseCase{repo: repo}
}

// ListInput is pagination input.
type ListInput struct {
	UserID string
	Limit  int
	Cursor string
}

// Execute returns a paginated list of followers.
func (uc *ListFollowersUseCase) Execute(ctx context.Context, input ListInput) ([]*domainTL.Follow, string, int, error) {
	follows, cursor, err := uc.repo.ListFollowers(ctx, input.UserID, input.Limit, input.Cursor)
	if err != nil {
		return nil, "", 0, err
	}
	count, err := uc.repo.CountFollowers(ctx, input.UserID)
	if err != nil {
		return nil, "", 0, err
	}
	return follows, cursor, count, nil
}

