package transport

import (
	"errors"
	"net/http"
	"strconv"

	"github.com/go-chi/chi/v5"

	"github.com/nikitakovalevtaverz/chirp/internal/transport/middleware"
	usecaseTL "github.com/nikitakovalevtaverz/chirp/internal/usecase/timeline"
	"github.com/nikitakovalevtaverz/chirp/pkg/api"
)

// FollowUserResponse is a user summary in follow lists.
type FollowUserResponse struct {
	ID        string `json:"id"`
	Username  string `json:"username"`
	CreatedAt string `json:"created_at"`
}

// FollowHandler handles follow endpoints.
type FollowHandler struct {
	follow      *usecaseTL.FollowUseCase
	unfollow    *usecaseTL.UnfollowUseCase
	followers   *usecaseTL.ListFollowersUseCase
	following   *usecaseTL.ListFollowingUseCase
}

// NewFollowHandler creates a FollowHandler.
func NewFollowHandler(
	follow *usecaseTL.FollowUseCase,
	unfollow *usecaseTL.UnfollowUseCase,
	followers *usecaseTL.ListFollowersUseCase,
	following *usecaseTL.ListFollowingUseCase,
) *FollowHandler {
	return &FollowHandler{follow: follow, unfollow: unfollow, followers: followers, following: following}
}

// Follow handles POST /api/v1/users/{id}/follow
//
//	@Summary		Follow a user
//	@Security		BearerAuth
//	@Param			id	path	string	true	"User ID to follow"
//	@Success		204
//	@Failure		400	{object}	api.ProblemDetail
//	@Router			/users/{id}/follow [post]
func (h *FollowHandler) Follow(w http.ResponseWriter, r *http.Request) {
	userID, _ := middleware.UserIDFromContext(r.Context())
	targetID := chi.URLParam(r, "id")
	if err := h.follow.Execute(r.Context(), userID, targetID); err != nil {
		if errors.Is(err, usecaseTL.ErrCannotFollowSelf) {
			api.BadRequest(w, "cannot follow yourself")
			return
		}
		api.InternalError(w, "internal server error")
		return
	}
	api.RespondNoContent(w)
}

// Unfollow handles DELETE /api/v1/users/{id}/follow
//
//	@Summary		Unfollow a user
//	@Security		BearerAuth
//	@Param			id	path	string	true	"User ID to unfollow"
//	@Success		204
//	@Router			/users/{id}/follow [delete]
func (h *FollowHandler) Unfollow(w http.ResponseWriter, r *http.Request) {
	userID, _ := middleware.UserIDFromContext(r.Context())
	targetID := chi.URLParam(r, "id")
	if err := h.unfollow.Execute(r.Context(), userID, targetID); err != nil {
		api.InternalError(w, "internal server error")
		return
	}
	api.RespondNoContent(w)
}

// Followers handles GET /api/v1/users/{id}/followers
//
//	@Summary		List followers
//	@Param			id		path	string	true	"User ID"
//	@Param			limit	query	int		false	"Limit"
//	@Param			cursor	query	string	false	"Cursor"
//	@Success		200		{object}	api.PageResponse[FollowUserResponse]
//	@Router			/users/{id}/followers [get]
func (h *FollowHandler) Followers(w http.ResponseWriter, r *http.Request) {
	id := chi.URLParam(r, "id")
	limit, _ := strconv.Atoi(r.URL.Query().Get("limit"))
	limit = api.DefaultLimit(limit, 20, 50)
	cursor := r.URL.Query().Get("cursor")

	follows, nextCursor, total, err := h.followers.Execute(r.Context(), usecaseTL.ListInput{
		UserID: id, Limit: limit, Cursor: cursor,
	})
	if err != nil {
		api.InternalError(w, "internal server error")
		return
	}

	items := make([]FollowUserResponse, len(follows))
	for i, f := range follows {
		items[i] = FollowUserResponse{
			ID:        f.FollowerID,
			CreatedAt: f.CreatedAt.Format("2006-01-02T15:04:05Z"),
		}
	}

	api.RespondOK(w, map[string]any{
		"data":        items,
		"next_cursor": nextCursor,
		"has_more":    nextCursor != "",
		"total":       total,
	})
}

// Following handles GET /api/v1/users/{id}/following
//
//	@Summary		List following
//	@Param			id		path	string	true	"User ID"
//	@Param			limit	query	int		false	"Limit"
//	@Param			cursor	query	string	false	"Cursor"
//	@Success		200		{object}	api.PageResponse[FollowUserResponse]
//	@Router			/users/{id}/following [get]
func (h *FollowHandler) Following(w http.ResponseWriter, r *http.Request) {
	id := chi.URLParam(r, "id")
	limit, _ := strconv.Atoi(r.URL.Query().Get("limit"))
	limit = api.DefaultLimit(limit, 20, 50)
	cursor := r.URL.Query().Get("cursor")

	follows, nextCursor, total, err := h.following.Execute(r.Context(), usecaseTL.ListInput{
		UserID: id, Limit: limit, Cursor: cursor,
	})
	if err != nil {
		api.InternalError(w, "internal server error")
		return
	}

	items := make([]FollowUserResponse, len(follows))
	for i, f := range follows {
		items[i] = FollowUserResponse{
			ID:        f.FolloweeID,
			CreatedAt: f.CreatedAt.Format("2006-01-02T15:04:05Z"),
		}
	}

	api.RespondOK(w, map[string]any{
		"data":        items,
		"next_cursor": nextCursor,
		"has_more":    nextCursor != "",
		"total":       total,
	})
}

package memory

import (
	"context"
	"sort"
	"sync"

	"github.com/nikitakovalevtaverz/chirp/internal/domain/timeline"
)

// FollowRepo is an in-memory implementation of port.FollowRepository.
type FollowRepo struct {
	mu        sync.RWMutex
	followers map[string]map[string]bool // userID -> set of followerIDs
	following map[string]map[string]bool // userID -> set of followeeIDs
}

// NewFollowRepo creates an empty FollowRepo.
func NewFollowRepo() *FollowRepo {
	return &FollowRepo{
		followers: make(map[string]map[string]bool),
		following: make(map[string]map[string]bool),
	}
}

func (r *FollowRepo) Follow(_ context.Context, followerID, followeeID string) error {
	r.mu.Lock()
	defer r.mu.Unlock()
	if r.following[followerID] == nil {
		r.following[followerID] = make(map[string]bool)
	}
	if r.followers[followeeID] == nil {
		r.followers[followeeID] = make(map[string]bool)
	}
	r.following[followerID][followeeID] = true
	r.followers[followeeID][followerID] = true
	return nil
}

func (r *FollowRepo) Unfollow(_ context.Context, followerID, followeeID string) error {
	r.mu.Lock()
	defer r.mu.Unlock()
	if r.following[followerID] != nil {
		delete(r.following[followerID], followeeID)
	}
	if r.followers[followeeID] != nil {
		delete(r.followers[followeeID], followerID)
	}
	return nil
}

func (r *FollowRepo) IsFollowing(_ context.Context, followerID, followeeID string) (bool, error) {
	r.mu.RLock()
	defer r.mu.RUnlock()
	set := r.following[followerID]
	return set != nil && set[followeeID], nil
}

func (r *FollowRepo) ListFollowers(_ context.Context, userID string, limit int, cursor string) ([]*timeline.Follow, string, error) {
	r.mu.RLock()
	defer r.mu.RUnlock()
	set := r.followers[userID]
	return paginateIDs(set, limit, cursor, true), "", nil
}

func (r *FollowRepo) ListFollowing(_ context.Context, userID string, limit int, cursor string) ([]*timeline.Follow, string, error) {
	r.mu.RLock()
	defer r.mu.RUnlock()
	set := r.following[userID]
	return paginateIDs(set, limit, cursor, false), "", nil
}

func (r *FollowRepo) CountFollowers(_ context.Context, userID string) (int, error) {
	r.mu.RLock()
	defer r.mu.RUnlock()
	return len(r.followers[userID]), nil
}

func (r *FollowRepo) CountFollowing(_ context.Context, userID string) (int, error) {
	r.mu.RLock()
	defer r.mu.RUnlock()
	return len(r.following[userID]), nil
}

func paginateIDs(set map[string]bool, limit int, cursor string, follower bool) []*timeline.Follow {
	if limit <= 0 || limit > 50 {
		limit = 20
	}
	ids := make([]string, 0, len(set))
	for id := range set {
		ids = append(ids, id)
	}
	sort.Strings(ids)

	start := 0
	if cursor != "" {
		for i, id := range ids {
			if id == cursor {
				start = i + 1
				break
			}
		}
	}
	end := start + limit
	if end > len(ids) {
		end = len(ids)
	}

	result := make([]*timeline.Follow, 0, end-start)
	for _, id := range ids[start:end] {
		f := &timeline.Follow{}
		if follower {
			f.FollowerID = id
			f.FolloweeID = ""
		} else {
			f.FollowerID = ""
			f.FolloweeID = id
		}
		result = append(result, f)
	}
	return result
}

