package timeline

import "time"

// Entry is a single item in a user's home timeline.
type Entry struct {
	RecipientID string    // user who sees this
	TweetID     string
	AuthorID    string
	ScoredAt    time.Time
}

package port

import (
	"context"

	"github.com/nikitakovalevtaverz/chirp/internal/domain/timeline"
)

// TimelineRepository manages home timeline entries.
type TimelineRepository interface {
	AddEntry(ctx context.Context, e *timeline.Entry) error
	GetHomeTimeline(ctx context.Context, userID string, limit int, cursor string) ([]*timeline.Entry, string, error)
}

package memory

import (
	"context"
	"sort"
	"sync"

	"github.com/nikitakovalevtaverz/chirp/internal/domain/timeline"
)

// TimelineRepo is an in-memory implementation of port.TimelineRepository.
type TimelineRepo struct {
	mu      sync.RWMutex
	entries map[string][]*timeline.Entry // userID -> entries (sorted by scored_at desc, then id desc)
}

// NewTimelineRepo creates an empty TimelineRepo.
func NewTimelineRepo() *TimelineRepo {
	return &TimelineRepo{entries: make(map[string][]*timeline.Entry)}
}

func (r *TimelineRepo) AddEntry(_ context.Context, e *timeline.Entry) error {
	r.mu.Lock()
	defer r.mu.Unlock()
	e.ScoredAt = e.ScoredAt.UTC()
	r.entries[e.RecipientID] = append(r.entries[e.RecipientID], e)
	return nil
}

func (r *TimelineRepo) GetHomeTimeline(_ context.Context, userID string, limit int, cursor string) ([]*timeline.Entry, string, error) {
	r.mu.RLock()
	defer r.mu.RUnlock()
	if limit <= 0 || limit > 50 {
		limit = 20
	}

	entries := r.entries[userID]

	// Sort by scored_at desc, tweet_id desc
	sort.Slice(entries, func(i, j int) bool {
		if entries[i].ScoredAt.Equal(entries[j].ScoredAt) {
			return entries[i].TweetID > entries[j].TweetID
		}
		return entries[i].ScoredAt.After(entries[j].ScoredAt)
	})

	start := 0
	if cursor != "" {
		for i, e := range entries {
			if e.TweetID == cursor {
				start = i + 1
				break
			}
		}
	}
	end := start + limit
	if end > len(entries) {
		end = len(entries)
	}

	nextCursor := ""
	if end < len(entries) {
		nextCursor = entries[end-1].TweetID
	}

	return entries[start:end], nextCursor, nil
}

package timeline

import (
	"context"

	"github.com/nikitakovalevtaverz/chirp/internal/port"
)

// GetHomeTimelineUseCase returns the home timeline for a user.
type GetHomeTimelineUseCase struct {
	timelineRepo port.TimelineRepository
}

// NewGetHomeTimelineUseCase creates a GetHomeTimelineUseCase.
func NewGetHomeTimelineUseCase(timelineRepo port.TimelineRepository) *GetHomeTimelineUseCase {
	return &GetHomeTimelineUseCase{timelineRepo: timelineRepo}
}

// Execute returns a paginated home timeline.
func (uc *GetHomeTimelineUseCase) Execute(ctx context.Context, userID string, limit int, cursor string) ([]*domainTimeline.Entry, string, error) {
	return uc.timelineRepo.GetHomeTimeline(ctx, userID, limit, cursor)
}

package timeline

import (
	"context"
	"time"

	"github.com/nikitakovalevtaverz/chirp/internal/port"
)

// FanOutUseCase distributes a tweet to followers' timelines.
type FanOutUseCase struct {
	timelineRepo port.TimelineRepository
	followRepo   port.FollowRepository
}

// NewFanOutUseCase creates a FanOutUseCase.
func NewFanOutUseCase(
	timelineRepo port.TimelineRepository,
	followRepo port.FollowRepository,
) *FanOutUseCase {
	return &FanOutUseCase{timelineRepo: timelineRepo, followRepo: followRepo}
}

// Execute fans out a tweet to all followers of the author.
func (uc *FanOutUseCase) Execute(ctx context.Context, tweetID, authorID string) error {
	// Get all followers (no pagination — we need ALL for fan-out)
	follows, _, err := uc.followRepo.ListFollowers(ctx, authorID, 100000, "")
	if err != nil {
		return err
	}

	now := time.Now().UTC()
	for _, f := range follows {
		entry := &domainTimeline.Entry{
			RecipientID: f.FollowerID,
			TweetID:     tweetID,
			AuthorID:    authorID,
			ScoredAt:    now,
		}
		if err := uc.timelineRepo.AddEntry(ctx, entry); err != nil {
			return err
		}
	}
	return nil
}

