func TestProblemDetail_Error(t *testing.T) {
	w := httptest.NewRecorder()
	api.NotFound(w, "user not found")

	resp := w.Result()
	if resp.StatusCode != http.StatusNotFound {
		t.Fatalf("expected 404, got %d", resp.StatusCode)
