// Package tracing initializes OpenTelemetry and exports traces to Phoenix/Arize.
package tracing

import (
	"context"
	"log/slog"
	"time"

	"go.opentelemetry.io/otel"
	"go.opentelemetry.io/otel/attribute"
	"go.opentelemetry.io/otel/exporters/otlp/otlptrace/otlptracegrpc"
	"go.opentelemetry.io/otel/sdk/resource"
	sdktrace "go.opentelemetry.io/otel/sdk/trace"
	semconv "go.opentelemetry.io/otel/semconv/v1.30.0"
	"go.opentelemetry.io/otel/trace"
)

// TracerProvider wraps a shutdown-able OTel SDK TracerProvider.
type TracerProvider struct {
	*sdktrace.TracerProvider
}

// InitPhoenix creates an OTel TracerProvider that exports traces to Phoenix.
// endpoint: "localhost:4317" (Phoenix gRPC port).
// Returns a nil provider if endpoint is empty (tracing disabled).
func InitPhoenix(ctx context.Context, endpoint, serviceName string) (*TracerProvider, error) {
	if endpoint == "" {
		slog.Info("OpenTelemetry disabled — PHOENIX_ENDPOINT not set")
		return nil, nil
	}

	ctx, cancel := context.WithTimeout(ctx, 5*time.Second)
	defer cancel()

	exporter, err := otlptracegrpc.New(ctx,
		otlptracegrpc.WithEndpoint(endpoint),
		otlptracegrpc.WithInsecure(),
	)
	if err != nil {
		return nil, err
	}

	res, err := resource.New(ctx,
		resource.WithAttributes(
			semconv.ServiceNameKey.String(serviceName),
			attribute.String("service.version", "1.0.0"),
		),
	)
	if err != nil {
		return nil, err
	}

	bsp := sdktrace.NewBatchSpanProcessor(exporter)
	tp := sdktrace.NewTracerProvider(
		sdktrace.WithSampler(sdktrace.AlwaysSample()),
		sdktrace.WithResource(res),
		sdktrace.WithSpanProcessor(bsp),
	)

	otel.SetTracerProvider(tp)

	slog.Info("OpenTelemetry connected", "endpoint", endpoint, "service", serviceName)
	return &TracerProvider{TracerProvider: tp}, nil
}

// Tracer returns a named tracer.
func Tracer(name string) trace.Tracer {
	return otel.Tracer(name)
}

// Shutdown gracefully flushes and shuts down the tracer provider.
func (tp *TracerProvider) Shutdown(ctx context.Context) error {
	if tp == nil || tp.TracerProvider == nil {
		return nil
	}
	return tp.TracerProvider.Shutdown(ctx)
}

